---

# 🧱 **1. stableStringify.ts**  
Deterministic JSON — key‑sorted, whitespace‑free, byte‑stable.

```ts
export function stableStringify(obj: any): string {
  if (Array.isArray(obj)) {
    return `[${obj.map(stableStringify).join(",")}]`;
  }
  if (obj && typeof obj === "object") {
    const keys = Object.keys(obj).sort();
    return `{${keys.map(k => `"${k}":${stableStringify(obj[k])}`).join(",")}}`;
  }
  return JSON.stringify(obj);
}
```

---

# 🔐 **2. hash.ts**  
Pure SHA‑256, hex output.

```ts
import { createHash } from "crypto";

export function sha256(data: string): string {
  return createHash("sha256").update(data).digest("hex");
}
```

---

# 📦 **3. exportAnalysis.ts**  
Writes `analysis.json` + `analysis.sha256` with reproducible formatting.

```ts
import fs from "fs";
import { stableStringify } from "./stableStringify";
import { sha256 } from "./hash";

export function exportAnalysis(analysis: any) {
  const json = stableStringify(analysis);
  const hash = sha256(json);

  fs.writeFileSync("./analysis.json", json);
  fs.writeFileSync("./analysis.sha256", `${hash}  analysis.json\n`);

  console.log("✔ analysis.json written");
  console.log("🔒 SHA-256:", hash);

  return hash;
}
```

