### `src/matrix/testMatrix.ts`

```ts
export type Env = "preview" | "production";
export type Mode = "streaming" | "non-streaming";
export type Risk = "low" | "medium" | "high";
export type Decision = "model" | "defer" | "reject";
export type Auth = "protected" | "bypass";

export type Vector = {
  env: Env;
  mode: Mode;
  risk: Risk;
  decision: Decision;
  auth: Auth;
};

export type AllocatorResponse = {
  headers: Record<string, string>;
  autoApproved: boolean;
  apiCalls: number;
  latency: number;
  stream?: boolean;
};
```

---

### `src/matrix/constraints.ts`

```ts
import type { Vector } from "./testMatrix";

export function isValidVector(v: Vector): boolean {
  if (v.mode === "streaming" && v.decision !== "model") return false;
  if (v.risk === "high" && v.auth === "bypass") return false;
  if (v.decision === "reject" && v.mode === "streaming") return false;
  return true;
}
```

---

### `src/matrix/generator.ts`

```ts
import type {
  Vector,
  Env,
  Mode,
  Risk,
  Decision,
  Auth,
} from "./testMatrix";
import { isValidVector } from "./constraints";

const ENVS: Env[] = ["preview", "production"];
const MODES: Mode[] = ["streaming", "non-streaming"];
const RISKS: Risk[] = ["low", "medium", "high"];
const DECISIONS: Decision[] = ["model", "defer", "reject"];
const AUTHS: Auth[] = ["protected", "bypass"];

export function generateAllVectors(): Vector[] {
  const out: Vector[] = [];

  for (const env of ENVS) {
    for (const mode of MODES) {
      for (const risk of RISKS) {
        for (const decision of DECISIONS) {
          for (const auth of AUTHS) {
            const v: Vector = { env, mode, risk, decision, auth };
            if (isValidVector(v)) {
              out.push(v);
            }
          }
        }
      }
    }
  }

  return out;
}
```

