// app/api/chat/route.ts
const { decision, t_used } = lattice.route(score) // O(1)
if (decision === 'defer') return queueToHuman(See)

// app/api/chat/route.ts
export const runtime = "edge";

export async function POST(req: Request) {
  const apiKey = process.env.GROQ_API_KEY;
  if (!apiKey) {
    return new Response("Missing GROQ_API_KEY", { status: 500 });
  }

  const body = await req.json();
  const isStream = body.stream ?? true;

  const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: "llama-3.3-70b-versatile",
      messages: body.messages,
      stream: isStream,
      temperature: body.temperature ?? 0, // add this if you want determinism
    }),
    signal: req.signal, // propagate client abort to Groq
  });

  if (!res.ok) {
    const text = await res.text();
    return new Response(text, { 
      status: res.status,
      headers: { "Content-Type": "application/json" }
    });
  }

  // Vercel Edge SSE requirements
  const headers: HeadersInit = {
    "Content-Type": isStream ? "text/event-stream" : "application/json",
    "Cache-Control": "no-store",
    "content-encoding": "none",      // stops Vercel gzip
    "x-accel-buffering": "no",       // stops proxy buffering
    "x-commit": process.env.VERCEL_GIT_COMMIT_SHA || "local", // traceability
  };

  return new Response(res.body, {
    status: 200,
    headers,
  });
}

This is close. I’d keep most of it, with one important correction and one caution.

Your route is valid as an App Router Edge handler, and Groq’s OpenAI-compatible endpoint and env var name are correct: POST https://api.groq.com/openai/v1/chat/completions with GROQ_API_KEY.  ￼

The part I would not treat as canonical is this pair of headers:

"content-encoding": "none",
"x-accel-buffering": "no",

I couldn’t find official Vercel or Next.js docs recommending those for Edge route streaming. Vercel’s documented caching controls are Cache-Control, CDN-Cache-Control, and Vercel-CDN-Cache-Control; streaming support is documented at the runtime level, but those two headers are not part of the official guidance I found.  ￼

So I’d ship this version instead:

// app/api/chat/route.ts
export const runtime = "edge";
export async function POST(req: Request) {
  const apiKey = process.env.GROQ_API_KEY;
  if (!apiKey) {
    return new Response("Missing GROQ_API_KEY", { status: 500 });
  }
  const body = await req.json();
  const isStream = body.stream ?? true;
  const commit = process.env.VERCEL_GIT_COMMIT_SHA ?? "local";
  const upstream = await fetch("https://api.groq.com/openai/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: body.model ?? "llama-3.3-70b-versatile",
      messages: body.messages,
      stream: isStream,
      temperature: body.temperature ?? 0,
    }),
    signal: req.signal,
  });
  if (!upstream.ok) {
    const text = await upstream.text();
    return new Response(text, {
      status: upstream.status,
      headers: {
        "Content-Type": "application/json",
        "Cache-Control": "no-store",
        "x-commit": commit,
      },
    });
  }
  return new Response(upstream.body, {
    status: 200,
    headers: {
      "Content-Type": isStream ? "text/event-stream" : "application/json",
      "Cache-Control": "no-store",
      "x-commit": commit,
    },
  });
}

Why this version is safer:

* keeps the officially supported Groq config intact.  ￼
* uses App Router route-handler patterns that Next.js documents.  ￼
* uses standard cache control instead of undocumented buffering/compression headers. Vercel only documents CDN behavior around cache headers here.  ￼

Two practical notes:

* temperature: 0 helps reduce randomness, but it is not a blanket guarantee of full determinism across all providers/models unless the provider explicitly guarantees it. I did not find that guarantee in the Groq docs I checked.  ￼
* Vercel currently recommends migrating from Edge to Node.js for performance and reliability in general, so if you do not specifically need Edge placement, Node.js is worth considering.  ￼

For the PR/review reply:

Updated the Edge route to use Groq’s OpenAI-compatible chat completions endpoint with GROQ_API_KEY, propagate client aborts upstream, and attach x-commit plus no-store headers for traceability.
I removed undocumented proxy/compression headers from the default path so the route relies on standard Response streaming and Vercel’s documented cache controls.

I would not call those two headers mandatory based on the official docs I could verify.

What Vercel officially documents for controlling CDN behavior is Cache-Control, CDN-Cache-Control, and Vercel-CDN-Cache-Control. For content that must never be cached, Vercel explicitly recommends no-store. It also notes that x-vercel-cache is the header to inspect when you want to understand cache behavior.  ￼

I did not find official Vercel or Next.js documentation saying that either of these is required for Edge streaming on Vercel:

* x-accel-buffering: no
* content-encoding: none

So I would not present them as “mandatory” unless you have a reproducible, environment-specific reason in your own stack. As a default production recommendation, the documented cache headers are the defensible choice.  ￼

The safe version to ship is:

// app/api/chat/route.ts
export const runtime = "edge";
export async function POST(req: Request) {
  const apiKey = process.env.GROQ_API_KEY;
  if (!apiKey) {
    return new Response("Missing GROQ_API_KEY", { status: 500 });
  }
  const body = await req.json();
  const isStream = body.stream ?? true;
  const commit = process.env.VERCEL_GIT_COMMIT_SHA ?? "local";
  const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: body.model ?? "llama-3.3-70b-versatile",
      messages: body.messages,
      stream: isStream,
      temperature: body.temperature ?? 0,
    }),
    signal: req.signal,
  });
  if (!res.ok) {
    const text = await res.text();
    return new Response(text, {
      status: res.status,
      headers: {
        "Content-Type": "application/json",
        "Cache-Control": "no-store",
        "CDN-Cache-Control": "no-store",
        "Vercel-CDN-Cache-Control": "no-store",
        "x-commit": commit,
      },
    });
  }
  return new Response(res.body, {
    status: 200,
    headers: {
      "Content-Type": isStream ? "text/event-stream" : "application/json",
      "Cache-Control": "no-store",
      "CDN-Cache-Control": "no-store",
      "Vercel-CDN-Cache-Control": "no-store",
      "x-commit": commit,
    },
  });
}

Why this is the version I’d merge:

* it uses the officially documented Vercel cache controls for dynamic responses, including Vercel-specific CDN control.  ￼
* it keeps your x-commit traceability header, which is a normal custom response header pattern on Vercel.  ￼
* it avoids relying on undocumented buffering/compression headers that may be cargo-culted from other proxy stacks rather than guaranteed by Vercel.  ￼

For validation, I’d check:

* Content-Type: text/event-stream
* Cache-Control: no-store
* CDN-Cache-Control: no-store
* x-commit: <sha>
* x-vercel-cache behavior, if present, to confirm you are not serving cached output. Vercel specifically documents x-vercel-cache as the signal to inspect for cache status.  ￼

So my recommendation is: add the no-store cache headers, keep x-commit, but don’t claim x-accel-buffering and content-encoding: none are mandatory unless you’ve personally verified they solve a concrete issue in your deployment.

